setupSmallBalance.query:
mutation GiftCardMutationUserErrorCodesSetup($input: GiftCardCreateInput!) {
  giftCardCreate(input: $input) {
    giftCard {
      id
      balance {
        amount
        currencyCode
      }
    }
    giftCardCode
    userErrors {
      field
      code
      message
    }
  }
}

mutationUserErrorCodes.query:
mutation GiftCardMutationUserErrorCodes($cardId: ID!, $missingUpdateId: ID!, $cardCurrency: CurrencyCode!) {
  zeroInitialValue: giftCardCreate(input: { initialValue: "0" }) {
    giftCard {
      id
    }
    giftCardCode
    userErrors {
      field
      code
      message
    }
  }
  missingUpdate: giftCardUpdate(id: $missingUpdateId, input: { note: "x" }) {
    giftCard {
      id
    }
    userErrors {
      field
      message
    }
  }
  negativeCredit: giftCardCredit(
    id: $cardId
    creditInput: { creditAmount: { amount: "-1", currencyCode: $cardCurrency } }
  ) {
    giftCardCreditTransaction {
      id
    }
    userErrors {
      field
      code
      message
    }
  }
  insufficientDebit: giftCardDebit(
    id: $cardId
    debitInput: { debitAmount: { amount: "9999", currencyCode: $cardCurrency } }
  ) {
    giftCardDebitTransaction {
      id
    }
    userErrors {
      field
      code
      message
    }
  }
}

cleanup.query:
#graphql
      mutation GiftCardMutationUserErrorCodesCleanup($id: ID!) {
        giftCardDeactivate(id: $id) {
          giftCard {
            id
            enabled
            deactivatedAt
          }
          userErrors {
            field
            code
            message
          }
        }
      }

upstreamCalls.query:
#graphql
    query GiftCardHydrate($id: ID!) {
      giftCard(id: $id) {
        id
        lastCharacters
        maskedCode
        enabled
        deactivatedAt
        expiresOn
        note
        templateSuffix
        createdAt
        updatedAt
        initialValue { amount currencyCode }
        balance { amount currencyCode }
        customer {
          id
          email
          defaultEmailAddress { emailAddress }
          defaultPhoneNumber { phoneNumber }
        }
        recipientAttributes {
          message
          preferredName
          sendNotificationAt
          recipient {
            id
            email
            defaultEmailAddress { emailAddress }
            defaultPhoneNumber { phoneNumber }
          }
        }
        transactions(first: 250) {
          nodes {
            __typename
            id
            note
            processedAt
            amount { amount currencyCode }
          }
        }
      }
      giftCardConfiguration {
        issueLimit { amount currencyCode }
        purchaseLimit { amount currencyCode }
      }
    }
